const raw = $input.first().json;
const d = raw.body || raw;
const now = new Date();
const submitTime = now.toLocaleTimeString('zh-TW', { hour: '2-digit', minute: '2-digit', hour12: false });
const weekday = new Date(d.date + 'T00:00:00').toLocaleDateString('zh-TW', { weekday: 'long' });
const safeStr = s => (s || '').slice(0, 30);
const fileName = `${d.date}_${safeStr(d.contractor)}_${safeStr(d.projectName)}.pdf`;
const photoUrls = d.photoUrls || [];
return [{ json: { ...d, submitTime, weekday, fileName, photoUrls, photoCount: photoUrls.length } }];

const d = $input.first().json;
const photoUrls = d.photoUrls || [];
const esc = s => String(s || '-').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
let photoHtml = '';
if (photoUrls.length > 0) {
  for (let i = 0; i < photoUrls.length; i += 4) {
    const chunk = photoUrls.slice(i, i + 4);
    const cells = chunk.map(url => `<td style='width:50%;padding:4px'><img src='${url}' style='width:100%;height:auto'></td>`);
    while (cells.length < 4) cells.push(`<td style='width:50%;padding:4px'></td>`);
    photoHtml += `<table style='width:100%;border-collapse:collapse;margin-top:8px;page-break-inside:avoid'><tr>${cells.slice(0,2).join('')}</tr><tr>${cells.slice(2,4).join('')}</tr></table>`;
  }
}
const html = `<!DOCTYPE html><html><head><meta charset='UTF-8'><style>body{font-family:Arial,sans-serif;font-size:10pt;margin:0}.t{text-align:center;font-weight:bold;margin-bottom:4px}table.m{width:100%;border-collapse:collapse}table.m td{border:1px solid #333;padding:4px 6px;vertical-align:top}.sh{background:#ddd;font-weight:bold;text-align:center}.c{min-height:40px;white-space:pre-wrap}</style></head><body><div class='t' style='font-size:14pt'>ECO INFINIC</div><div class='t' style='font-size:12pt;margin-bottom:8px'>監工人員工作日誌</div><table class='m'><tr><td style='width:12%'><b>工程名稱</b></td><td style='width:38%'>${esc(d.projectName)}</td><td style='width:12%'><b>施工廠區</b></td><td style='width:38%'>${esc(d.constructionArea)}</td></tr><tr><td><b>日期</b></td><td>${esc(d.date)}</td><td><b>星期</b></td><td>${esc(d.weekday)}</td></tr><tr><td><b>天氣</b></td><td colspan='3'>上午: ${esc(d.morningWeather)} / 下午: ${esc(d.afternoonWeather)}</td></tr><tr><td><b>時間</b></td><td colspan='3'>${esc(d.submitTime)}</td></tr><tr><td class='sh' colspan='4'>施工部位</td></tr><tr><td colspan='4' class='c'>${esc(d.constructionLocation)}</td></tr><tr><td class='sh' colspan='4'>工作內容</td></tr><tr><td><b>施工項目</b></td><td colspan='3' class='c' style='min-height:60px'>${esc(d.constructionItems)}</td></tr><tr><td><b>供給材料使用</b></td><td>${esc(d.materialsUsed)}</td><td><b>機具使用</b></td><td>${esc(d.equipment)}</td></tr><tr><td><b>出工人數</b></td><td colspan='3'>${esc(d.workers)} 人</td></tr><tr><td class='sh' colspan='4'>與廠商溝通協調記錄</td></tr><tr><td colspan='4' class='c'>${esc(d.communication)}</td></tr><tr><td class='sh' colspan='4'>其他重要事項記錄</td></tr><tr><td colspan='4' class='c'>${esc(d.otherNotes)}</td></tr><tr><td colspan='2'><b>施工取樣試驗記錄</b></td><td colspan='2'><b>品質、數量檢查記錄</b></td></tr><tr><td colspan='2' class='c'>${esc(d.samplingTests)}</td><td colspan='2' class='c'>${esc(d.qualityInspection)}</td></tr><tr><td><b>單位主管</b></td><td></td><td><b>監工人員</b></td><td>${esc(d.supervisor)}</td></tr></table>${photoHtml}</body></html>`;
return [{ json: { ...d, pdfHtml: html } }];

const prepData = $('Prepare Data').first().json;
const driveFileId = $('Google Drive Upload').first().json.id;
const driveUrl = 'https://drive.google.com/file/d/' + driveFileId + '/view';
const lang = prepData.language || 'en';
const isEn = lang !== 'th';
const contractorFlex = { to: prepData.lineUserId, messages: [{ type: 'flex', altText: isEn ? 'Work Report Ready' : 'รายงานงานพร้อมแล้ว', contents: { type: 'bubble', header: { type: 'box', layout: 'vertical', backgroundColor: '#1a73e8', contents: [{ type: 'text', text: isEn ? 'Work Report Ready' : 'รายงานงานพร้อมแล้ว', color: '#ffffff', weight: 'bold', size: 'lg' }] }, body: { type: 'box', layout: 'vertical', spacing: 'sm', contents: [{ type: 'text', text: (isEn ? 'Date' : 'วันที่') + ': ' + prepData.date, size: 'sm', color: '#555555' }, { type: 'text', text: (isEn ? 'Project' : 'โครงการ') + ': ' + prepData.projectName, size: 'sm', color: '#555555' }, { type: 'text', text: (isEn ? 'Photos' : 'รูปภาพ') + ': ' + prepData.photoCount, size: 'sm', color: '#555555' }] }, footer: { type: 'box', layout: 'vertical', contents: [{ type: 'button', style: 'primary', color: '#1a73e8', action: { type: 'uri', label: isEn ? 'Download PDF Report' : 'ดาวน์โหลดรายงาน PDF', uri: driveUrl } }] } } }] };
const jerryFlex = { to: 'REPLACE_WITH_JERRY_LINE_USER_ID', messages: [{ type: 'flex', altText: '監工日誌報告已生成', contents: { type: 'bubble', header: { type: 'box', layout: 'vertical', backgroundColor: '#0d7a0d', contents: [{ type: 'text', text: '監工日誌報告已生成', color: '#ffffff', weight: 'bold', size: 'lg' }] }, body: { type: 'box', layout: 'vertical', spacing: 'sm', contents: [{ type: 'text', text: '日期: ' + prepData.date, size: 'sm', color: '#555555' }, { type: 'text', text: '工程: ' + prepData.projectName, size: 'sm', color: '#555555' }, { type: 'text', text: '廠商: ' + prepData.contractor, size: 'sm', color: '#555555' }, { type: 'text', text: '照片: ' + prepData.photoCount + ' 張', size: 'sm', color: '#555555' }] }, footer: { type: 'box', layout: 'vertical', contents: [{ type: 'button', style: 'primary', color: '#0d7a0d', action: { type: 'uri', label: '下載 PDF 報告', uri: driveUrl } }] } } }] };
return [{ json: { contractorPayload: JSON.stringify(contractorFlex), jerryPayload: JSON.stringify(jerryFlex) } }];
